// Log Job Result â€” Refiner workflow.
// Assembles the refinement result for: Model Usage Recorder, Resume Recorder, and the
// webhook response. One refiner agent ran (Polisher=agent_6 for polish, Refiner=agent_9
// for refine), plus optional verifier and the scorer. Cost computed from tokens Ã— pricing.

const safeGet = (nodeName) => {
  try { return $(nodeName)?.first()?.json ?? null; }
  catch (err) { console.log(`[Refiner Log] Node '${nodeName}' not found`); return null; }
};

const req = $('Set Inputs').first().json;
const pricing = $('Data Loader').first().json.pricing || {};
const runId = $('Data Loader').first().json.run_id || '';   // refine_<execution.id>
const mode = req.mode;                                       // 'polish' | 'refine'

const computeCost = (sub, rates) => {
  if (!rates || !sub) return 0;
  return (sub.tokens?.input || 0) / 1e6 * (rates.input_per_million || 0) +
         (sub.tokens?.output || 0) / 1e6 * (rates.output_per_million || 0) +
         (sub.cached_input_tokens || 0) / 1e6 * (rates.cached_input_per_million || 0) +
         (sub.cache_write_tokens || 0) / 1e6 * (rates.cache_write_per_million || 0);
};
const missingPricing = new Set();
const costFor = (sub, agentId) => {
  if (!sub) return 0;
  const model = sub.model_used || '';
  if (!model || model === 'skipped' || model === 'crash' || model === 'unknown') return 0;
  const rates = pricing[model] || null;
  if (!rates) { console.log(`[Refiner Log] no pricing for "${model}" (${agentId})`); missingPricing.add(`${agentId}:${model}`); }
  return computeCost(sub, rates);
};

// The refiner agent that ran, by mode.
const refinerNode = (mode === 'polish') ? 'Resume Polisher' : 'Resume Refiner';
const refinerAgentId = (mode === 'polish') ? 'agent_6' : 'agent_9';
const refinerOut = safeGet(refinerNode);
const verifierOut = safeGet('Resume Verifier');   // null if verifier gate was false
const scorerOut = safeGet('Resume Scorer');
const resolved = safeGet('Resolve Resume');

const finalMarkdown = resolved?.resume_markdown || refinerOut?.resume_markdown || '';

const costRefiner = costFor(refinerOut, refinerAgentId);
const costVerifier = costFor(verifierOut, 'agent_3');
const costScorer = costFor(scorerOut, 'agent_7');

// Score delta vs the parent version (parent_score sent in the request).
// Gate on scorer success: a FAILED scorer reports overall_score:0, which is a
// number and would otherwise compute a bogus delta (e.g. 0 - 88 = -88). Only a
// successful score is a real score; otherwise newScore is null â†’ delta null.
const newScore = (scorerOut?.success === true && typeof scorerOut?.overall_score === 'number')
  ? scorerOut.overall_score : null;
const parentScore = (typeof req.parent_score === 'number') ? req.parent_score : null;
const scoreDelta = (newScore !== null && parentScore !== null) ? (newScore - parentScore) : null;

// New version number = parent + 1.
const newVersion = (Number(req.parent_version) || 0) + 1;

// error_log: original failures only (not cascaded).
const errorLog = [];
const addErr = (id, sub) => {
  if (sub && sub.success === false && sub.cascaded !== true) {
    errorLog.push(`${id}:${sub.error?.category || 'unknown'}`);
  }
};
addErr(refinerAgentId, refinerOut);
addErr('agent_3', verifierOut);
addErr('agent_7', scorerOut);
for (const entry of missingPricing) errorLog.push(`data_loader:missing_pricing:${entry}`);

const refinementCost = costRefiner + costVerifier + costScorer;
const hasFailure = [refinerOut, verifierOut, scorerOut].some(a => a && a.success === false);

// Credit detection: did any sub fail specifically on insufficient_credit?
const hasInsufficientCredit = [refinerOut, verifierOut, scorerOut]
  .some(a => a && a.success === false && a.cascaded !== true && a.error?.category === 'insufficient_credit');

const result = {
  run_id: runId,
  mode,
  application_run_id: req.application_run_id || '',
  job: {
    job_id: req.job_id || '',
    company: req.company || '',
    title: req.title || '',
    url: req.url || ''
  },

  // Refiner agent sub (named by mode in MUR). Carries the new resume.
  refiner: {
    success: refinerOut?.success || false,
    cascaded: refinerOut?.cascaded || false,
    resume_markdown: finalMarkdown,
    tokens: refinerOut?.tokens || { input: 0, output: 0 },
    cached_input_tokens: refinerOut?.cached_input_tokens || 0,
    cache_write_tokens: refinerOut?.cache_write_tokens || 0,
    cost: costRefiner,
    model_used: refinerOut?.model_used || 'unknown',
    provider_used: refinerOut?.provider_used || 'unknown',
    error: refinerOut?.error || null
  },
  verifier: {
    ran: !!verifierOut,
    success: verifierOut?.success || false,
    cascaded: verifierOut?.cascaded || false,
    verdict: verifierOut?.result?.verdict || 'unknown',
    unsupported_count: verifierOut?.result?.unsupported_count || 0,
    issues: verifierOut?.result?.issues || [],
    tokens: verifierOut?.tokens || { input: 0, output: 0 },
    cached_input_tokens: verifierOut?.cached_input_tokens || 0,
    cache_write_tokens: verifierOut?.cache_write_tokens || 0,
    cost: costVerifier,
    model_used: verifierOut?.model_used || 'unknown',
    provider_used: verifierOut?.provider_used || 'unknown',
    error: verifierOut?.error || null
  },
  scorer: {
    success: scorerOut?.success || false,
    cascaded: scorerOut?.cascaded || false,
    overall_score: newScore,
    recommendation: scorerOut?.recommendation || 'unknown',
    dimensions: scorerOut?.dimensions || {},
    strengths: scorerOut?.strengths || [],
    gaps: scorerOut?.gaps || [],
    rationale: scorerOut?.rationale || scorerOut?.score_rationale || '',
    tokens: scorerOut?.tokens || { input: 0, output: 0 },
    cached_input_tokens: scorerOut?.cached_input_tokens || 0,
    cache_write_tokens: scorerOut?.cache_write_tokens || 0,
    cost: costScorer,
    model_used: scorerOut?.model_used || 'unknown',
    provider_used: scorerOut?.provider_used || 'unknown',
    error: scorerOut?.error || null
  },

  // resume_row: consumed by Resume Recorder to write the new resumes-tab row.
  resume_row: {
    version: newVersion,
    source: (mode === 'polish') ? 'polish' : 'refinement',
    parent_resume_id: req.parent_resume_id || '',
    refinement_instructions: req.refinement_instructions || '',
    score_delta: scoreDelta
  },

  refinement_cost: Number(refinementCost.toFixed(6)),
  refinement_tokens: {
    input: (refinerOut?.tokens?.input || 0) + (verifierOut?.tokens?.input || 0) + (scorerOut?.tokens?.input || 0),
    output: (refinerOut?.tokens?.output || 0) + (verifierOut?.tokens?.output || 0) + (scorerOut?.tokens?.output || 0)
  },
  error_log: errorLog,
  processed_status: hasInsufficientCredit ? 'insufficient_credit' : (hasFailure ? 'error' : 'done'),
  credit_event: hasInsufficientCredit,
  generated_at: new Date().toISOString()
};

console.log(`[Refiner Log] mode=${mode} run=${runId} job=${result.job.job_id} v${newVersion} score=${newScore} delta=${scoreDelta} cost=$${refinementCost.toFixed(4)} status=${result.processed_status}`);

return [{ json: result }];

// Resolve Resume (Refiner): produce the refined/polished markdown as the result.
// Two arrival paths into this node:
//   - Verifier ran (gate true)   â†’ incoming item is Resume Verifier's output,
//                                   which AUDITS the resume and does NOT carry
//                                   the markdown. Must read markdown from the refiner.
//   - Verifier skipped (gate false) â†’ incoming item is the refiner output (has markdown).
// So we source markdown from the refiner node by mode (Polisher=polish, Refiner=refine),
// and fall back to the incoming item only if the refiner lookup misses.
const item = $input.item.json;

// Workflow inputs are owned by Set Inputs (the refiner webhook entry).
const inputs = $('Set Inputs').item.json;

// The refiner that ran, by mode. This is the authoritative source of the new markdown.
const refinerNode = (inputs.mode === 'polish') ? 'Resume Polisher' : 'Resume Refiner';
let refinerMarkdown = '';
try {
  refinerMarkdown = $(refinerNode).first().json.resume_markdown || '';
} catch (err) {
  console.log(`[Resolve Resume] refiner node '${refinerNode}' not reachable: ${err.message}`);
}

const resumeMarkdown =
  refinerMarkdown ||
  item.resume_markdown ||
  item.result?.resume_markdown ||
  '';

if (!resumeMarkdown) {
  console.log('[Resolve Resume] WARNING: empty resume_markdown after all fallbacks.');
}

return {
  json: {
    resume_markdown: resumeMarkdown,
    refined: true,
    ran_verifier: inputs.run_verifier === true || String(inputs.run_verifier).toLowerCase().trim() === 'true',
    refinement_instructions: inputs.refinement_instructions || '',
    parent_version: inputs.parent_version || 0,
    mode: inputs.mode || 'refine'
  }
};

// Set Inputs â€” Refiner webhook entry.
// Parses + validates the dashboard's /refine request. Two modes:
//   refine â†’ user instructions drive the revision (Agent 9)
//   polish â†’ original run's critic + verifier drive it (Agent 6)
// Provider/model/max_tokens are NOT accepted from the request â€” they are config-only
// (config.*_refiner), resolved inside Agents 6/9. The dashboard shows them read-only.
// The dashboard sends parent markdown + JD + (for polish) the V1 critic/verifier,
// so the refiner needs no sheet lookups.

const body = $input.first().json.body || $input.first().json || {};

const mode = String(body.mode || 'refine').toLowerCase().trim();

const req = {
  mode,
  application_run_id: String(body.application_run_id || '').trim(),
  parent_resume_id: String(body.parent_resume_id || '').trim(),
  parent_resume_markdown: String(body.parent_resume_markdown || ''),
  refinement_instructions: String(body.refinement_instructions || '').trim(),
  run_verifier: body.run_verifier !== false,   // default ON
  parent_ran_verifier: body.parent_ran_verifier === true || String(body.parent_ran_verifier).toLowerCase().trim() === 'true',
  // Job context (sent by dashboard so no jobs-sheet read):
  job_id: String(body.job_id || '').trim(),
  url: String(body.url || '').trim(),
  company: String(body.company || '').trim(),
  title: String(body.title || '').trim(),
  jd_text: String(body.jd_text || body.description_html || body.jd_summary || ''),
  parent_version: Number(body.parent_version) || 0,
  parent_score: (typeof body.parent_score === 'number') ? body.parent_score : null,
  // Polish-only: the original run's findings, sent by the dashboard from agent_outputs.
  critic_output: body.critic_output || null,
  verifier_output: body.verifier_output || null
};

// Mode-aware validation â€” fail loud so the webhook returns a clear error.
const missing = [];
if (!req.parent_resume_id) missing.push('parent_resume_id');
if (!req.parent_resume_markdown) missing.push('parent_resume_markdown');
if (!req.job_id) missing.push('job_id');

// Both paths require instructions (collected in UI for polish and refine alike).
if (!req.refinement_instructions) missing.push('refinement_instructions');

if (req.mode === 'polish') {
  // First refinement: feeds Agent 6 the ORIGINAL run's stored findings (both required).
  if (!req.critic_output)   missing.push('critic_output (required for polish)');
  if (!req.verifier_output) missing.push('verifier_output (required for polish)');
} else if (req.mode === 'refine') {
  // Subsequent: parent's verifier_output required only if the parent pass ran verifier.
  if (req.parent_ran_verifier && !req.verifier_output) {
    missing.push('verifier_output (required for refine when parent pass ran verifier)');
  }
} else {
  throw new Error(`[Refiner Set Inputs] Unknown mode '${req.mode}' â€” expected 'refine' or 'polish'`);
}

if (missing.length) {
  throw new Error(`[Refiner Set Inputs] Missing required field(s): ${missing.join(', ')}`);
}

console.log(`[Refiner Set Inputs] mode=${req.mode} job_id=${req.job_id} parent=${req.parent_resume_id} v${req.parent_version} verifier=${req.run_verifier}`);

return [{ json: req }];

// Build Response â€” runs after Resume Recorder; read the refiner result from Log Job Result.
const jr = $('Log Job Result').first().json;
const scorer = jr.scorer || {};
const verifier = jr.verifier || {};
const row = jr.resume_row || {};
const jobId = jr.job?.job_id || '';
const version = Number(row.version) || 2;

const delta = (typeof row.score_delta === 'number') ? row.score_delta : 0;
const lowImprovement = delta < 3;
let improvementMessage = '';
if (delta < 0) {
  improvementMessage = `This version scored ${Math.abs(delta)} point(s) lower than the previous one. You may want to revert or revise your instructions.`;
} else if (delta < 3) {
  improvementMessage = `Only +${delta} since the previous version. Consider changing your instructions for a bigger improvement, or stop here.`;
}

const ok = jr.processed_status === 'done';

return [{
  json: {
    ok,
    mode: jr.mode,
    resume_id: `${jobId}_v${version}`,
    version,
    resume_markdown: jr.refiner?.resume_markdown || '',
    overall_score: (typeof scorer.overall_score === 'number') ? scorer.overall_score : null,
    score_delta: delta,
    low_improvement: lowImprovement,
    improvement_message: improvementMessage,
    verifier_verdict: verifier.verdict || null,
    unsupported_count: (typeof verifier.unsupported_count === 'number') ? verifier.unsupported_count : null,
    critic_critical_count: null,
    cost_usd: (typeof jr.refinement_cost === 'number') ? jr.refinement_cost : 0,
    error: ok ? null : (jr.error_log || []).join('; ')
  }
}];
